sql:
SELECT MAX(data_size) AS largest_csv_data_size
FROM observational_data
WHERE data_format = 'CSV';

SELECT data_format, AVG(data_size) AS average_data_size, COUNT(data_id) AS count_of_files
FROM observational_data
GROUP BY data_format;

SELECT observatory_name
FROM observatories
WHERE elevation = (SELECT MAX(elevation) FROM observatories);

SELECT observatory_name
FROM observatories
WHERE funding_source = 'NASA';

SELECT quality_rating
FROM data_quality
WHERE confidence_level = (SELECT MAX(confidence_level) FROM data_quality);

